import React from "react";
import UploadImage from "./UploadImage";

function App() {
  return (
    <div className="min-h-screen bg-gray-100 flex flex-col items-center justify-center p-6">
      <h1 className="text-4xl font-bold text-gray-900 mb-4">Radiology AI App</h1>
      <p className="text-lg text-gray-700 mb-6">Upload Medical Image for AI Analysis</p>

      {/* Upload Section */}
      <UploadImage />

      {/* AI Report Section */}
      <div className="mt-6 w-full max-w-3xl bg-white shadow-md rounded-lg p-6">
        <h2 className="text-2xl font-semibold text-gray-800 mb-3">AI Report:</h2>
        <p className="text-gray-700 leading-relaxed text-justify">
          This image is a **CT scan of the chest** at the level of the lungs. Here's what I observe...
        </p>
      </div>
    </div>
  );
}

export default App;
